import type { DialogueEntry } from '../../../types';
import { CharacterId } from '../../../characters';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "餐廳裡掛著百年校慶的紅色布條，空氣裡混著豆漿和油條的味道，還有一層薄薄的興奮。今天是特別的日子，每個人都這麼覺得。", background: "chapter_1/ch1_act2_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "除了顧言。", background: "chapter_1/ch1_act2_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他端著餐盤，在角落找了一個空位坐下。背對著人群，面對著牆壁。這是他的習慣——不是因為害羞，是因為背對人群的時候，就不需要看見別人看他的眼神。", background: "chapter_1/ch1_act2_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那種眼神他太熟了。半好奇，半害怕，帶著一點點試探，像在動物園看一隻不知道會不會咬人的動物。有些人會壓低聲音跟旁邊的人說什麼，有些人會假裝沒看見他，有些人會故意大聲提到「十年前那件事」。", background: "chapter_1/ch1_act2_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他都聽過了。每一種。", background: "chapter_1/ch1_act2_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他咬了一口油條。不脆，有點韌，大概是昨天的。他不在意。", background: "chapter_1/ch1_act2_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "餐廳另一頭的公告牆上貼著今天的活動時程表。他遠遠地看了一眼：", background: "chapter_1/ch1_act2_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "校史展全天開放。百年時間膠囊展示基座晚間移至禮堂。晚間閉幕典禮會直播。因天氣不穩，部分戶外活動可能調整。", background: "chapter_1/ch1_act2_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)時間膠囊。又一個可以拿來炒作校史的道具。", background: "chapter_1/ch1_act2_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他其實不太在意校慶。校慶這種東西對他來說只有一個意義：一定會提到十年前火災。因為火災是鳴海高中近二十年來最大的事件，校史展板上一定會有，閉幕典禮的致辭裡一定會提。", background: "chapter_1/ch1_act2_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "每次提到火災，就會有人想起「那個縱火犯」。然後就會有人想起「那個縱火犯的兒子」。然後他就會變成今天的主角——不是那種會讓人鼓掌的主角。", background: "chapter_1/ch1_act2_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他正想著，一個聲音從斜後方傳來。", background: "chapter_1/ch1_act2_s0" },
    { characterId: CharacterId.Student, character: "同學A", dialogue: "欸你看，那邊那個就是顧言吧？", background: "chapter_1/ch1_act2_s0" },
    { characterId: CharacterId.Student, character: "同學B", dialogue: "(小聲)噓，小聲一點啦。", background: "chapter_1/ch1_act2_s0" },
    { characterId: CharacterId.Student, character: "同學A", dialogue: "(小聲)反正他聽不到⋯⋯我是說，他爸以前是不是也在這間學校？", background: "chapter_1/ch1_act2_s0" },
    { characterId: CharacterId.Student, character: "同學B", dialogue: "(小聲)對啊，好像是校慶那天出事的。好誇張喔，百年校慶又碰到這種事⋯⋯", background: "chapter_1/ch1_act2_s0" },
    { characterId: CharacterId.Student, character: "同學A", dialogue: "(小聲)你說他會不會也去鐘樓？聽說那邊晚上會有特別活動⋯⋯", background: "chapter_1/ch1_act2_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言的筷子停在半空中。", background: "chapter_1/ch1_act2_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "三秒。他把油條放下，端起餐盤站起來，經過那兩個同學身邊的時候，腳步沒有停，眼神也沒有轉過去。他只是把餐盤放回回收台，然後走出了餐廳。", background: "chapter_1/ch1_act2_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "身後的對話安靜了一瞬，然後又恢復了，只是音量更低了。", background: "chapter_1/ch1_act2_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走廊上的風很大，帶著海水的鹹味和雨水的潮氣。布條被吹得啪啪作響，上面寫著「鳴海高中百年校慶」幾個大字，紅底金字，喜氣洋洋。", background: "chapter_1/ch1_act2_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言站在走廊上，手插在口袋裡，看著遠處被雨霧遮住的鐘樓。", background: "chapter_1/ch1_act2_s1" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)今天好長。", background: "chapter_1/ch1_act2_s1", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)現在才八點。", background: "chapter_1/ch1_act2_s1", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他深吸一口氣，轉身往校園廣場的方向走去。不管他想不想，他都被安排了校慶志工的工作。搬東西、掛布條、當人形立牌。反正都是那種「不會有人注意、也不會有人感謝」的工作。", background: "chapter_1/ch1_act2_s1" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)剛好。", background: "chapter_1/ch1_act2_s1", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他走進雨裡。沒有撐傘。雨不大，只是細細的、綿綿的，像一層薄紗蓋在校園上方，把所有東西都變得模糊。", background: "chapter_1/ch1_act2_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "校園廣場上已經架起了舞台和帳篷，學生和家長來來往往。有人在測試音響，有人在排椅子，有人在掛燈籠。一塊巨大的電子螢幕立在舞台旁邊，正在測試校慶直播畫面，畫面閃了幾下，然後穩定下來，顯示「鳴海高中百年校慶直播」幾個字。", background: "chapter_1/ch1_act2_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言繞過人群，走向校史館方向。班導之前在群組裡說，需要幾個人去校史館幫忙搬展覽箱，他報了名。不是因為他想去，是因為那邊人最少。", background: "chapter_1/ch1_act2_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "路過公告牆的時候，他看見幾名學生站在「十年前南翼樓火災紀念角」的展板前面。展板上的文字他看過無數次了——「前校友顧某涉嫌人為縱火，造成多人受傷」。", background: "chapter_1/ch1_act2_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "沒有寫名字。永遠不會寫名字。只用「顧某」兩個字帶過，像一塊遮羞布，既承認了事件的存在，又迴避了真正的責任歸屬。", background: "chapter_1/ch1_act2_s1" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)「顧某」。每次看到這兩個字，都想笑。", background: "chapter_1/ch1_act2_s1", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)學校既想利用火災做安全教育，又不願意真正談當年的責任。標題寫得冠冕堂皇，內容全都是模糊帶過。好像只要不寫名字，那個人就不存在一樣。", background: "chapter_1/ch1_act2_s1", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他收回視線，加快腳步。", background: "chapter_1/ch1_act2_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "雨還在下。", background: "chapter_1/ch1_act2_s1" },
];
